1	"use client";
2	
3	import { useState, useEffect, useCallback, useRef } from "react";
4	import styles from "@/app/styles/table.module.css";
5	
6	interface Hizmet {
7	  ID: number;
8	  Kod: string;
9	  Ad: string;
10	  AdEn: string;
11	  Method: string;
12	  MethodEn: string;
13	  Matriks: string;
14	  Akreditasyon: string;
15	  Sure: number | null;
16	  NumGereklilik: string;
17	  NumDipnot: string;
18	  NumDipnotEn: string;
19	  Fiyat: number | null;
20	  ParaBirimi: string;
21	  Durumu: string;
22	}
23	
24	const EMPTY: Partial<Hizmet> = {
25	  Kod: "", Ad: "", AdEn: "", Method: "", MethodEn: "",
26	  Matriks: "", Akreditasyon: "Yok", Sure: undefined,
27	  NumGereklilik: "", NumDipnot: "", NumDipnotEn: "",
28	  Fiyat: undefined, ParaBirimi: "₺", Durumu: "Aktif",
29	};
30	
31	export default function HizmetTable() {
32	  const [rows, setRows]         = useState<Hizmet[]>([]);
33	  const [total, setTotal]       = useState(0);
34	  const [page, setPage]         = useState(1);
35	  const [limit, setLimit]       = useState(20);
36	  const [totalPages, setTotalPages] = useState(1);
37	  const [search, setSearch]     = useState("");
38	  const [loading, setLoading]   = useState(true);
39	  const [error, setError]       = useState("");
40	
41	  // Modals
42	  const [detailRow, setDetailRow]   = useState<Hizmet | null>(null);
43	  const [editRow, setEditRow]       = useState<Partial<Hizmet> | null>(null);
44	  const [isNew, setIsNew]           = useState(false);
45	  const [saving, setSaving]         = useState(false);
46	  const [formError, setFormError]   = useState("");
47	
48	  const searchTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
49	
50	  const fetchData = useCallback(async (p: number, s: string, l: number) => {
51	    setLoading(true);
52	    setError("");
53	    try {
54	      const res = await fetch(
55	        `/api/hizmetler?page=${p}&limit=${l}&search=${encodeURIComponent(s)}`
56	      );
57	      if (!res.ok) throw new Error((await res.json()).error || "Hata");
58	      const json = await res.json();
59	      setRows(json.data);
60	      setTotal(json.total);
61	      setTotalPages(json.totalPages);
62	    } catch (e: any) {
63	      setError(e.message);
64	    } finally {
65	      setLoading(false);
66	    }
67	  }, []);
68	
69	  useEffect(() => { fetchData(page, search, limit); }, [page, limit]);
70	
71	  const handleSearch = (val: string) => {
72	    setSearch(val);
73	    if (searchTimer.current) clearTimeout(searchTimer.current);
74	    searchTimer.current = setTimeout(() => {
75	      setPage(1);
76	      fetchData(1, val, limit);
77	    }, 350);
78	  };
79	
80	  // ── Save (create / update) ──
81	  const handleSave = async () => {
82	    if (!editRow) return;
83	    setSaving(true);
84	    setFormError("");
85	    try {
86	      const url    = isNew ? "/api/hizmetler" : `/api/hizmetler/${editRow.ID}`;
87	      const method = isNew ? "POST" : "PUT";
88	      const res    = await fetch(url, {
89	        method,
90	        headers: { "Content-Type": "application/json" },
91	        body: JSON.stringify(editRow),
92	      });
93	      if (!res.ok) throw new Error((await res.json()).error || "Kayıt hatası");
94	      setEditRow(null);
95	      fetchData(page, search, limit);
96	    } catch (e: any) {
97	      setFormError(e.message);
98	    } finally {
99	      setSaving(false);
100	    }
101	  };
102	
103	  const openNew  = () => { setIsNew(true);  setFormError(""); setEditRow({ ...EMPTY }); };
104	  const openEdit = (row: Hizmet) => { setIsNew(false); setFormError(""); setEditRow({ ...row }); };
105	  const closeEdit = () => setEditRow(null);
106	
107	  // ── Pagination helpers ──
108	  const goTo = (p: number) => { if (p >= 1 && p <= totalPages) setPage(p); };
109	
110	  const pageNums = () => {
111	    const nums: (number | "…")[] = [];
112	    if (totalPages <= 7) {
113	      for (let i = 1; i <= totalPages; i++) nums.push(i);
114	    } else {
115	      nums.push(1);
116	      if (page > 3) nums.push("…");
117	      for (let i = Math.max(2, page - 1); i <= Math.min(totalPages - 1, page + 1); i++) nums.push(i);
118	      if (page < totalPages - 2) nums.push("…");
119	      nums.push(totalPages);
120	    }
121	    return nums;
122	  };
123	
124	  const fiyatLabel = (row: Hizmet) =>
125	    row.Fiyat != null ? `${row.Fiyat.toLocaleString("tr-TR")} ${row.ParaBirimi}` : "";
126	
127	  return (
128	    <>
129	      {/* ── Toolbar ── */}
130	      <div className={styles.toolbar}>
131	        <div className={styles.toolbarLeft}>
132	          <div className={styles.searchBox}>
133	            <svg className={styles.searchIcon} viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
134	              <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
135	            </svg>
136	            <input
137	              className={styles.searchInput}
138	              placeholder="Kod, ad veya metot ara…"
139	              value={search}
140	              onChange={e => handleSearch(e.target.value)}
141	            />
142	            {search && (
143	              <button className={styles.searchClear} onClick={() => handleSearch("")}>
144	                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
145	                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
146	                </svg>
147	              </button>
148	            )}
149	          </div>
150	          <span className={styles.totalCount}>{total} hizmet</span>
151	        </div>
152	        <div className={styles.toolbarRight}>
153	          <select
154	            className={styles.pageSizeSelect}
155	            value={limit}
156	            onChange={e => { setLimit(Number(e.target.value)); setPage(1); }}
157	          >
158	            {[10, 20, 50, 100].map(n => <option key={n} value={n}>{n} / sayfa</option>)}
159	          </select>
160	          <button className={styles.addBtn} onClick={openNew}>
161	            <svg viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
162	              <path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z" />
163	            </svg>
164	            Yeni Hizmet
165	          </button>
166	        </div>
167	      </div>
168	
169	      {/* ── Tablo ── */}
170	      <div className={styles.tableCard}>
171	        {error && <div className={styles.errorBar}>{error}</div>}
172	        <div className={styles.tableWrapper}>
173	          <table className={styles.table}>
174	            <thead>
175	              <tr>
176	                <th style={{ width: 24 }}></th>
177	                <th>Kod</th>
178	                <th>Ad</th>
179	                <th>Metot</th>
180	                <th>Matriks</th>
181	                <th>Süre (gün)</th>
182	                <th>Numune Gereklilik</th>
183	                <th>Liste Fiyatı</th>
184	                <th style={{ width: 100 }}></th>
185	              </tr>
186	            </thead>
187	            <tbody>
188	              {loading ? (
189	                Array.from({ length: 8 }).map((_, i) => (
190	                  <tr key={i}>
191	                    {Array.from({ length: 9 }).map((_, j) => (
192	                      <td key={j}><span className={styles.skeleton} /></td>
193	                    ))}
194	                  </tr>
195	                ))
196	              ) : rows.length === 0 ? (
197	                <tr>
198	                  <td colSpan={9}>
199	                    <div className={styles.empty}>
200	                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" width="36" height="36">
201	                        <path strokeLinecap="round" strokeLinejoin="round" d="M9.75 9.75l4.5 4.5m0-4.5l-4.5 4.5M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
202	                      </svg>
203	                      Kayıt bulunamadı
204	                    </div>
205	                  </td>
206	                </tr>
207	              ) : rows.map((row, idx) => (
208	                <tr key={row.ID}>
209	                  <td className={styles.tdNum}
210	                    style={{ textAlign: "center", fontWeight: 700, fontSize: "0.82rem", color: "#0071e3" }}>
211	                    {row.Akreditasyon === "Var" ? "*" : ""}
212	                  </td>
213	                  <td className={styles.tdMono}>{row.Kod}</td>
214	                  <td className={styles.tdName}>{row.Ad}</td>
215	                  <td className={styles.tdSecondary}>{row.Method}</td>
216	                  <td className={styles.tdSecondary}>{row.Matriks}</td>
217	                  <td className={styles.tdMono}>{row.Sure ?? ""}</td>
218	                  <td className={styles.tdSecondary}>{row.NumGereklilik}</td>
219	                  <td className={styles.tdMono}>{fiyatLabel(row)}</td>
220	                  <td>
221	                    <div className={styles.actionBtns}>
222	                      {/* Detaylar */}
223	                      <button
224	                        className={styles.editBtn}
225	                        title="Detaylar"
226	                        onClick={() => setDetailRow(row)}
227	                        style={{ width: "auto", padding: "0 8px", fontSize: "0.75rem", gap: 4 }}
228	                      >
229	                        <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
230	                          <path d="M10 12.5a2.5 2.5 0 1 0 0-5 2.5 2.5 0 0 0 0 5Z" />
231	                          <path fillRule="evenodd" d="M.664 10.59a1.651 1.651 0 0 1 0-1.186A10.004 10.004 0 0 1 10 3c4.257 0 7.893 2.66 9.336 6.41.147.381.146.804 0 1.186A10.004 10.004 0 0 1 10 17c-4.257 0-7.893-2.66-9.336-6.41ZM14 10a4 4 0 1 1-8 0 4 4 0 0 1 8 0Z" clipRule="evenodd" />
232	                        </svg>
233	                        Detay
234	                      </button>
235	                      {/* Düzenle */}
236	                      <button
237	                        className={styles.editBtn}
238	                        title="Düzenle"
239	                        onClick={() => openEdit(row)}
240	                      >
241	                        <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
242	                          <path d="M5.433 13.917l1.262-3.155A4 4 0 0 1 7.58 9.42l6.92-6.918a2.121 2.121 0 0 1 3 3l-6.92 6.918c-.383.383-.84.685-1.343.886l-3.154 1.262a.5.5 0 0 1-.65-.65Z" />
243	                          <path d="M3.5 5.75c0-.69.56-1.25 1.25-1.25H10A.75.75 0 0 0 10 3H4.75A2.75 2.75 0 0 0 2 5.75v9.5A2.75 2.75 0 0 0 4.75 18h9.5A2.75 2.75 0 0 0 17 15.25V10a.75.75 0 0 0-1.5 0v5.25c0 .69-.56 1.25-1.25 1.25h-9.5c-.69 0-1.25-.56-1.25-1.25v-9.5Z" />
244	                        </svg>
245	                      </button>
246	                    </div>
247	                  </td>
248	                </tr>
249	              ))}
250	            </tbody>
251	          </table>
252	        </div>
253	
254	        {/* ── Sayfalama ── */}
255	        {totalPages > 1 && (
256	          <div className={styles.pagination}>
257	            <button className={styles.pageBtn} onClick={() => goTo(page - 1)} disabled={page === 1}>‹</button>
258	            {pageNums().map((n, i) =>
259	              n === "…"
260	                ? <span key={`d${i}`} className={styles.pageDots}>…</span>
261	                : <button
262	                    key={n}
263	                    className={`${styles.pageBtn} ${page === n ? styles.pageBtnActive : ""}`}
264	                    onClick={() => goTo(n as number)}
265	                  >{n}</button>
266	            )}
267	            <button className={styles.pageBtn} onClick={() => goTo(page + 1)} disabled={page === totalPages}>›</button>
268	            <span className={styles.pageInfo}>{total} kayıt</span>
269	          </div>
270	        )}
271	      </div>
272	
273	      {/* ══════════════════════════════════════════════
274	          DETAY POPUP
275	      ══════════════════════════════════════════════ */}
276	      {detailRow && (
277	        <div className={styles.modalOverlay} onClick={() => setDetailRow(null)}>
278	          <div className={styles.modal} style={{ maxWidth: 560 }} onClick={e => e.stopPropagation()}>
279	            <div className={styles.modalHeader}>
280	              <h2>{detailRow.Kod} — {detailRow.Ad}</h2>
281	              <button className={styles.modalClose} onClick={() => setDetailRow(null)}>
282	                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
283	                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z"/>
284	                </svg>
285	              </button>
286	            </div>
287	            <div className={styles.modalBody}>
288	              <DetailSection label="Türkçe" items={[
289	                ["Akreditasyon", detailRow.Akreditasyon === "Var" ? "Var ✓" : "Yok"],
290	                ["Ad",           detailRow.Ad],
291	                ["Metot",        detailRow.Method],
292	                ["Matriks",      detailRow.Matriks],
293	                ["Süre (gün)",   detailRow.Sure != null ? String(detailRow.Sure) : "—"],
294	                ["Numune Gereklilik", detailRow.NumGereklilik || "—"],
295	                ["Dipnot",       detailRow.NumDipnot || "—"],
296	                ["Fiyat",        fiyatLabel(detailRow) || "—"],
297	              ]} />
298	              <div style={{ height: 16 }} />
299	              <DetailSection label="English" items={[
300	                ["Name",         detailRow.AdEn    || "—"],
301	                ["Method",       detailRow.MethodEn || "—"],
302	                ["Note",         detailRow.NumDipnotEn || "—"],
303	              ]} />
304	            </div>
305	          </div>
306	        </div>
307	      )}
308	
309	      {/* ══════════════════════════════════════════════
310	          DÜZENLE / YENİ EKLEME FORMU
311	      ══════════════════════════════════════════════ */}
312	      {editRow && (
313	        <div className={styles.modalOverlay} onClick={closeEdit}>
314	          <div className={styles.modal} style={{ maxWidth: 680 }} onClick={e => e.stopPropagation()}>
315	            <div className={styles.modalHeader}>
316	              <h2>{isNew ? "Yeni Hizmet" : `Düzenle — ${editRow.Kod}`}</h2>
317	              <button className={styles.modalClose} onClick={closeEdit}>
318	                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
319	                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z"/>
320	                </svg>
321	              </button>
322	            </div>
323	            <div className={styles.modalBody}>
324	              {formError && <div className={styles.formError}>{formError}</div>}
325	
326	              {/* Satır 1: Kod + Akreditasyon + Matriks */}
327	              <div className={styles.formGrid3} style={{ marginBottom: 14 }}>
328	                <div className={styles.formGroup}>
329	                  <label>Kod <span className={styles.required}>*</span></label>
330	                  <input value={editRow.Kod || ""} onChange={e => setEditRow(p => ({ ...p!, Kod: e.target.value }))} />
331	                </div>
332	                <div className={styles.formGroup}>
333	                  <label>Akreditasyon</label>
334	                  <select value={editRow.Akreditasyon || "Yok"} onChange={e => setEditRow(p => ({ ...p!, Akreditasyon: e.target.value }))}>
335	                    <option value="Var">Var</option>
336	                    <option value="Yok">Yok</option>
337	                  </select>
338	                </div>
339	                <div className={styles.formGroup}>
340	                  <label>Matriks</label>
341	                  <input value={editRow.Matriks || ""} onChange={e => setEditRow(p => ({ ...p!, Matriks: e.target.value }))} />
342	                </div>
343	              </div>
344	
345	              {/* Satır 2: Ad + AdEn */}
346	              <div className={styles.formGrid} style={{ marginBottom: 14 }}>
347	                <div className={styles.formGroup}>
348	                  <label>Ad (TR) <span className={styles.required}>*</span></label>
349	                  <input value={editRow.Ad || ""} onChange={e => setEditRow(p => ({ ...p!, Ad: e.target.value }))} />
350	                </div>
351	                <div className={styles.formGroup}>
352	                  <label>Ad (EN)</label>
353	                  <input value={editRow.AdEn || ""} onChange={e => setEditRow(p => ({ ...p!, AdEn: e.target.value }))} />
354	                </div>
355	              </div>
356	
357	              {/* Satır 3: Method TR + Method EN */}
358	              <div className={styles.formGrid} style={{ marginBottom: 14 }}>
359	                <div className={styles.formGroup}>
360	                  <label>Metot (TR)</label>
361	                  <input value={editRow.Method || ""} onChange={e => setEditRow(p => ({ ...p!, Method: e.target.value }))} />
362	                </div>
363	                <div className={styles.formGroup}>
364	                  <label>Metot (EN)</label>
365	                  <input value={editRow.MethodEn || ""} onChange={e => setEditRow(p => ({ ...p!, MethodEn: e.target.value }))} />
366	                </div>
367	              </div>
368	
369	              {/* Satır 4: Süre + NumGereklilik + Fiyat + Para */}
370	              <div className={styles.formGrid} style={{ marginBottom: 14 }}>
371	                <div className={styles.formGroup}>
372	                  <label>Süre (gün)</label>
373	                  <input type="number" min={0} value={editRow.Sure ?? ""} onChange={e => setEditRow(p => ({ ...p!, Sure: e.target.value ? Number(e.target.value) : undefined }))} />
374	                </div>
375	                <div className={styles.formGroup}>
376	                  <label>Numune Gereklilik</label>
377	                  <input value={editRow.NumGereklilik || ""} onChange={e => setEditRow(p => ({ ...p!, NumGereklilik: e.target.value }))} />
378	                </div>
379	              </div>
380	              <div className={styles.formGrid} style={{ marginBottom: 14 }}>
381	                <div className={styles.formGroup}>
382	                  <label>Fiyat</label>
383	                  <input type="number" min={0} step="0.01" value={editRow.Fiyat ?? ""} onChange={e => setEditRow(p => ({ ...p!, Fiyat: e.target.value ? Number(e.target.value) : undefined }))} />
384	                </div>
385	                <div className={styles.formGroup}>
386	                  <label>Para Birimi</label>
387	                  <select value={editRow.ParaBirimi || "₺"} onChange={e => setEditRow(p => ({ ...p!, ParaBirimi: e.target.value }))}>
388	                    <option value="₺">₺ — Türk Lirası</option>
389	                    <option value="$">$ — Dolar</option>
390	                    <option value="€">€ — Euro</option>
391	                  </select>
392	                </div>
393	              </div>
394	
395	              {/* Satır 5: Dipnot TR */}
396	              <div className={styles.formGroup} style={{ marginBottom: 14 }}>
397	                <label>Dipnot (TR)</label>
398	                <textarea rows={2} value={editRow.NumDipnot || ""} onChange={e => setEditRow(p => ({ ...p!, NumDipnot: e.target.value }))} />
399	              </div>
400	
401	              {/* Satır 6: Dipnot EN */}
402	              <div className={styles.formGroup} style={{ marginBottom: 14 }}>
403	                <label>Dipnot (EN)</label>
404	                <textarea rows={2} value={editRow.NumDipnotEn || ""} onChange={e => setEditRow(p => ({ ...p!, NumDipnotEn: e.target.value }))} />
405	              </div>
406	
407	              {/* Durum — sadece düzenlemede göster */}
408	              {!isNew && (
409	                <div className={styles.formGroup}>
410	                  <label>Durum</label>
