"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import styles from "@/app/styles/table.module.css";

interface Numune {
  ID: number;
  Tarih: string | null;
  Evrak_No: string;
  RaporNo: string;
  FirmaAd: string | null;
  ProjeAd: string | null;
  Numune_Adi: string;
  Grup: string | null;
  Tur: string | null;
  Odeme_Durumu: string | null;
}

const EMPTY: Partial<Numune> & { Firma_ID?: string } = {
  Tarih: new Date().toISOString().split("T")[0],
  Evrak_No: "",
  RaporNo: "",
  Firma_ID: "",
  Numune_Adi: "",
  Grup: "",
};

export default function NumuneKabulTable() {
  const [rows, setRows]             = useState<Numune[]>([]);
  const [total, setTotal]           = useState(0);
  const [page, setPage]             = useState(1);
  const [limit, setLimit]           = useState(20);
  const [totalPages, setTotalPages] = useState(1);
  const [search, setSearch]         = useState("");
  const [loading, setLoading]       = useState(true);
  const [error, setError]           = useState("");

  // Modals
  const [editRow, setEditRow]   = useState<(Partial<Numune> & { Firma_ID?: string }) | null>(null);
  const [isNew, setIsNew]       = useState(false);
  const [saving, setSaving]     = useState(false);
  const [formError, setFormError] = useState("");
  const [deleteId, setDeleteId] = useState<number | null>(null);
  const [deleting, setDeleting] = useState(false);

  const searchTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const fetchData = useCallback(async (p: number, s: string, l: number) => {
    setLoading(true);
    setError("");
    try {
      const res = await fetch(
        `/api/numune-kabul?page=${p}&limit=${l}&search=${encodeURIComponent(s)}`
      );
      if (!res.ok) throw new Error((await res.json()).error || "Hata");
      const json = await res.json();
      setRows(json.data);
      setTotal(json.total);
      setTotalPages(json.totalPages);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(page, search, limit); }, [page, limit]);

  const handleSearch = (val: string) => {
    setSearch(val);
    if (searchTimer.current) clearTimeout(searchTimer.current);
    searchTimer.current = setTimeout(() => {
      setPage(1);
      fetchData(1, val, limit);
    }, 350);
  };

  // ── Save ──
  const handleSave = async () => {
    if (!editRow) return;
    setSaving(true);
    setFormError("");
    try {
      const url    = isNew ? "/api/numune-kabul" : `/api/numune-kabul/${editRow.ID}`;
      const method = isNew ? "POST" : "PUT";
      const res    = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(editRow),
      });
      if (!res.ok) throw new Error((await res.json()).error || "Kayıt hatası");
      setEditRow(null);
      fetchData(page, search, limit);
    } catch (e: any) {
      setFormError(e.message);
    } finally {
      setSaving(false);
    }
  };

  // ── Soft delete ──
  const handleDelete = async () => {
    if (!deleteId) return;
    setDeleting(true);
    try {
      const res = await fetch(`/api/numune-kabul/${deleteId}`, { method: "DELETE" });
      if (!res.ok) throw new Error((await res.json()).error || "Silinemedi");
      setDeleteId(null);
      fetchData(page, search, limit);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setDeleting(false);
    }
  };

  const openNew  = () => { setIsNew(true);  setFormError(""); setEditRow({ ...EMPTY }); };
  const openEdit = (row: Numune) => {
    setIsNew(false);
    setFormError("");
    setEditRow({ ...row, Firma_ID: "" });
  };
  const closeEdit = () => setEditRow(null);

  // ── Pagination ──
  const goTo = (p: number) => { if (p >= 1 && p <= totalPages) setPage(p); };

  const pageNums = () => {
    const nums: (number | "…")[] = [];
    if (totalPages <= 7) {
      for (let i = 1; i <= totalPages; i++) nums.push(i);
    } else {
      nums.push(1);
      if (page > 3) nums.push("…");
      for (let i = Math.max(2, page - 1); i <= Math.min(totalPages - 1, page + 1); i++) nums.push(i);
      if (page < totalPages - 2) nums.push("…");
      nums.push(totalPages);
    }
    return nums;
  };

  const formatTarih = (tarih: string | null) => {
    if (!tarih) return "";
    const [y, m, d] = tarih.split("-");
    return `${d}.${m}.${y}`;
  };

  const odemeBadge = (durum: string | null) => {
    if (!durum) return null;
    const color =
      durum === "Ödendi"   ? "#34c759" :
      durum === "Bekliyor" ? "#ff9500" : "#8e8e93";
    return (
      <span style={{
        display: "inline-block", padding: "2px 8px",
        borderRadius: 10, fontSize: "0.73rem", fontWeight: 600,
        background: `${color}18`, color,
      }}>{durum}</span>
    );
  };

  const COLS = 10;

  return (
    <>
      {/* ── Toolbar ── */}
      <div className={styles.toolbar}>
        <div className={styles.toolbarLeft}>
          <div className={styles.searchBox}>
            <svg className={styles.searchIcon} viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
              <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
            </svg>
            <input
              className={styles.searchInput}
              placeholder="Evrak no, rapor no, firma veya numune ara…"
              value={search}
              onChange={e => handleSearch(e.target.value)}
            />
            {search && (
              <button className={styles.searchClear} onClick={() => handleSearch("")}>
                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
                </svg>
              </button>
            )}
          </div>
          <span className={styles.totalCount}>{total} numune</span>
        </div>
        <div className={styles.toolbarRight}>
          <select
            className={styles.pageSizeSelect}
            value={limit}
            onChange={e => { setLimit(Number(e.target.value)); setPage(1); }}
          >
            {[10, 20, 50, 100].map(n => <option key={n} value={n}>{n} / sayfa</option>)}
          </select>
          <button className={styles.addBtn} onClick={openNew}>
            <svg viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
              <path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z" />
            </svg>
            Yeni Numune
          </button>
        </div>
      </div>

      {/* ── Tablo ── */}
      <div className={styles.tableCard}>
        {error && <div className={styles.errorBar}>{error}</div>}
        <div className={styles.tableWrapper}>
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Tarih</th>
                <th>Evrak No</th>
                <th>Rapor No</th>
                <th>Firma</th>
                <th>Proje</th>
                <th>Numune Adı</th>
                <th>Grup</th>
                <th>Tür</th>
                <th>Ödeme</th>
                <th style={{ width: 90 }}></th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                Array.from({ length: 8 }).map((_, i) => (
                  <tr key={i}>
                    {Array.from({ length: COLS }).map((_, j) => (
                      <td key={j}><span className={styles.skeleton} /></td>
                    ))}
                  </tr>
                ))
              ) : rows.length === 0 ? (
                <tr>
                  <td colSpan={COLS}>
                    <div className={styles.empty}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" width="36" height="36">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M9.75 9.75l4.5 4.5m0-4.5l-4.5 4.5M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
                      </svg>
                      Kayıt bulunamadı
                    </div>
                  </td>
                </tr>
              ) : rows.map(row => (
                <tr key={row.ID}>
                  <td className={styles.tdMono}>{formatTarih(row.Tarih)}</td>
                  <td className={styles.tdMono}>{row.Evrak_No}</td>
                  <td className={styles.tdMono} style={{ fontWeight: 600, color: "var(--color-accent)" }}>{row.RaporNo}</td>
                  <td className={styles.tdSecondary}>{row.FirmaAd ?? "—"}</td>
                  <td className={styles.tdSecondary}>{row.ProjeAd ?? "—"}</td>
                  <td className={styles.tdName}>{row.Numune_Adi}</td>
                  <td className={styles.tdSecondary}>{row.Grup ?? "—"}</td>
                  <td className={styles.tdSecondary}>{row.Tur ?? "—"}</td>
                  <td>{odemeBadge(row.Odeme_Durumu)}</td>
                  <td>
                    <div className={styles.actionBtns}>
                      {/* Düzenle */}
                      <button
                        className={styles.editBtn}
                        title="Düzenle"
                        onClick={() => openEdit(row)}
                      >
                        <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
                          <path d="M5.433 13.917l1.262-3.155A4 4 0 0 1 7.58 9.42l6.92-6.918a2.121 2.121 0 0 1 3 3l-6.92 6.918c-.383.383-.84.685-1.343.886l-3.154 1.262a.5.5 0 0 1-.65-.65Z" />
                          <path d="M3.5 5.75c0-.69.56-1.25 1.25-1.25H10A.75.75 0 0 0 10 3H4.75A2.75 2.75 0 0 0 2 5.75v9.5A2.75 2.75 0 0 0 4.75 18h9.5A2.75 2.75 0 0 0 17 15.25V10a.75.75 0 0 0-1.5 0v5.25c0 .69-.56 1.25-1.25 1.25h-9.5c-.69 0-1.25-.56-1.25-1.25v-9.5Z" />
                        </svg>
                      </button>
                      {/* Sil */}
                      <button
                        className={styles.editBtn}
                        title="Pasife Al"
                        onClick={() => setDeleteId(row.ID)}
                        style={{ color: "#ff3b30" }}
                      >
                        <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
                          <path fillRule="evenodd" d="M8.75 1A2.75 2.75 0 0 0 6 3.75v.443c-.795.077-1.584.176-2.365.298a.75.75 0 1 0 .23 1.482l.149-.022.841 10.518A2.75 2.75 0 0 0 7.596 19h4.807a2.75 2.75 0 0 0 2.742-2.53l.841-10.52.149.023a.75.75 0 0 0 .23-1.482A41.03 41.03 0 0 0 14 4.193V3.75A2.75 2.75 0 0 0 11.25 1h-2.5ZM10 4c.84 0 1.673.025 2.5.075V3.75c0-.69-.56-1.25-1.25-1.25h-2.5c-.69 0-1.25.56-1.25 1.25v.325C8.327 4.025 9.16 4 10 4ZM8.58 7.72a.75.75 0 0 0-1.5.06l.3 7.5a.75.75 0 1 0 1.5-.06l-.3-7.5Zm4.34.06a.75.75 0 1 0-1.5-.06l-.3 7.5a.75.75 0 1 0 1.5.06l.3-7.5Z" clipRule="evenodd" />
                        </svg>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* ── Sayfalama ── */}
        {totalPages > 1 && (
          <div className={styles.pagination}>
            <button className={styles.pageBtn} onClick={() => goTo(page - 1)} disabled={page === 1}>‹</button>
            {pageNums().map((n, i) =>
              n === "…"
                ? <span key={`d${i}`} className={styles.pageDots}>…</span>
                : <button
                    key={n}
                    className={`${styles.pageBtn} ${page === n ? styles.pageBtnActive : ""}`}
                    onClick={() => goTo(n as number)}
                  >{n}</button>
            )}
            <button className={styles.pageBtn} onClick={() => goTo(page + 1)} disabled={page === totalPages}>›</button>
            <span className={styles.pageInfo}>{total} kayıt</span>
          </div>
        )}
      </div>

      {/* ══════════════════════════════════════════════
          DÜZENLE / YENİ EKLEME FORMU
      ══════════════════════════════════════════════ */}
      {editRow && (
        <div className={styles.modalOverlay} onClick={closeEdit}>
          <div className={styles.modal} style={{ maxWidth: 600 }} onClick={e => e.stopPropagation()}>
            <div className={styles.modalHeader}>
              <h2>{isNew ? "Yeni Numune" : `Düzenle — ${editRow.RaporNo || editRow.Evrak_No}`}</h2>
              <button className={styles.modalClose} onClick={closeEdit}>
                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
                </svg>
              </button>
            </div>
            <div className={styles.modalBody}>
              {formError && <div className={styles.formError}>{formError}</div>}

              {/* Tarih */}
              <div className={styles.formGroup} style={{ marginBottom: 14 }}>
                <label>Tarih</label>
                <input
                  type="date"
                  value={editRow.Tarih || ""}
                  onChange={e => setEditRow(p => ({ ...p!, Tarih: e.target.value }))}
                />
              </div>

              {/* Evrak No + Rapor No */}
              <div className={styles.formGrid} style={{ marginBottom: 14 }}>
                <div className={styles.formGroup}>
                  <label>Evrak No <span className={styles.required}>*</span></label>
                  <input
                    value={editRow.Evrak_No || ""}
                    onChange={e => setEditRow(p => ({ ...p!, Evrak_No: e.target.value }))}
                  />
                </div>
                <div className={styles.formGroup}>
                  <label>Rapor No <span className={styles.required}>*</span></label>
                  <input
                    value={editRow.RaporNo || ""}
                    onChange={e => setEditRow(p => ({ ...p!, RaporNo: e.target.value }))}
                  />
                </div>
              </div>

              {/* Numune Adı */}
              <div className={styles.formGroup} style={{ marginBottom: 14 }}>
                <label>Numune Adı <span className={styles.required}>*</span></label>
                <input
                  value={editRow.Numune_Adi || ""}
                  onChange={e => setEditRow(p => ({ ...p!, Numune_Adi: e.target.value }))}
                />
              </div>

              {/* Firma ID + Grup */}
              <div className={styles.formGrid} style={{ marginBottom: 14 }}>
                <div className={styles.formGroup}>
                  <label>Firma ID</label>
                  <input
                    type="number"
                    min={1}
                    value={editRow.Firma_ID || ""}
                    onChange={e => setEditRow(p => ({ ...p!, Firma_ID: e.target.value }))}
                    placeholder="Firma ID"
                  />
                </div>
                <div className={styles.formGroup}>
                  <label>Grup</label>
                  <input
                    value={editRow.Grup || ""}
                    onChange={e => setEditRow(p => ({ ...p!, Grup: e.target.value }))}
                  />
                </div>
              </div>
            </div>
            <div className={styles.modalFooter}>
              <button className={styles.cancelBtn} onClick={closeEdit} disabled={saving}>İptal</button>
              <button className={styles.saveBtn} onClick={handleSave} disabled={saving}>
                {saving ? <span className={styles.loader} /> : isNew ? "Kaydet" : "Güncelle"}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ══════════════════════════════════════════════
          SİLME ONAY POPUP
      ══════════════════════════════════════════════ */}
      {deleteId !== null && (
        <div className={styles.modalOverlay} onClick={() => setDeleteId(null)}>
          <div className={styles.modal} style={{ maxWidth: 400 }} onClick={e => e.stopPropagation()}>
            <div className={styles.modalHeader}>
              <h2>Pasife Al</h2>
              <button className={styles.modalClose} onClick={() => setDeleteId(null)}>
                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
                </svg>
              </button>
            </div>
            <div className={styles.modalBody}>
              <p style={{ fontSize: "0.9rem", color: "var(--color-text-secondary)" }}>
                Bu numune pasife alınacak ve listeden kaldırılacak. Devam etmek istiyor musunuz?
              </p>
            </div>
            <div className={styles.modalFooter}>
              <button className={styles.cancelBtn} onClick={() => setDeleteId(null)} disabled={deleting}>İptal</button>
              <button
                className={styles.saveBtn}
                onClick={handleDelete}
                disabled={deleting}
                style={{ background: "#ff3b30" }}
              >
                {deleting ? <span className={styles.loader} /> : "Pasife Al"}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

