.formGrid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
}
.formGrid3 {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 14px;
}
.colSpan2 { grid-column: 1 / span 2; }
.colSpan3 { grid-column: 1 / span 3; }

.formGroup {
  display: flex;
  flex-direction: column;
  gap: 5px;
