.required { color: var(--color-danger); }

.formGroup input,
.formGroup select,
.formGroup textarea {
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  background: var(--color-surface);
  color: var(--color-text-primary);
  padding: 8px 11px;
  font-size: 0.845rem;
  font-family: inherit;
  outline: none;
  transition: border-color 0.15s, box-shadow 0.15s;
  resize: vertical;
