.formGroup input:focus,
.formGroup select:focus,
.formGroup textarea:focus {
  border-color: var(--color-accent);
  box-shadow: 0 0 0 3px var(--color-accent-light);
}

.formGroup input::placeholder,
.formGroup textarea::placeholder { color: var(--color-text-tertiary); }

.modalFooter {
  display: flex;
  justify-content: flex-end;
  align-items: center;
  gap: 8px;
  padding: 14px 24px;
  border-top: 1px solid var(--color-border-light);
}

.cancelBtn {
  padding: 7px 16px;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-full);
  background: var(--color-surface);
  color: var(--color-text-secondary);
  font-size: 0.845rem;
  font-weight: 400;
  font-family: inherit;
  cursor: pointer;
  transition: var(--transition-fast);
}
.cancelBtn:hover:not(:disabled) {
  background: var(--color-surface-2);
}
.cancelBtn:disabled { opacity: 0.4; }

.saveBtn {
  padding: 7px 18px;
  border: none;
  border-radius: var(--radius-full);
  background: var(--color-accent);
  color: #fff;
  font-size: 0.845rem;
  font-weight: 500;
  font-family: inherit;
  cursor: pointer;
  transition: var(--transition-fast);
  min-width: 80px;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 34px;
}
.saveBtn:hover:not(:disabled) { background: var(--color-accent-hover); }
.saveBtn:active:not(:disabled) { transform: scale(0.98); }
.saveBtn:disabled {
  background: #a1c4ef;
  cursor: not-allowed;
}

.deleteBtnPrimary {
  padding: 7px 18px;
  border: none;
  border-radius: var(--radius-full);
  background: var(--color-danger);
  color: #fff;
  font-size: 0.845rem;
  font-weight: 500;
  font-family: inherit;
  cursor: pointer;
  min-width: 90px;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 34px;
  transition: var(--transition-fast);
}
.deleteBtnPrimary:hover:not(:disabled) { background: #e0321f; }
.deleteBtnPrimary:disabled { opacity: 0.4; cursor: not-allowed; }

.deleteWarning {
  color: var(--color-text-secondary);
  font-size: 0.875rem;
  line-height: 1.6;
}

.loader {
  width: 15px;
  height: 15px;
  border: 1.5px solid rgba(255, 255, 255, 0.35);
  border-radius: 50%;
  border-top-color: #fff;
  animation: spin 0.7s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

