import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import poolPromise from "@/lib/db";
import { type NextRequest } from "next/server";

// ----------------------------------------------------------------
// GET  /api/numune-kabul?search=&page=1&limit=20
// ----------------------------------------------------------------
export async function GET(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session) return Response.json({ error: "Yetkisiz erişim" }, { status: 401 });

  const sp     = request.nextUrl.searchParams;
  const search = sp.get("search")?.trim() || "";
  const page   = Math.max(1, parseInt(sp.get("page")  || "1",  10));
  const limit  = Math.min(100, Math.max(5, parseInt(sp.get("limit") || "20", 10)));
  const offset = (page - 1) * limit;

  try {
    const pool = await poolPromise;

    const searchClause = search
      ? `AND (
          n.Evrak_No   LIKE N'%' + @search + '%'
          OR n.RaporNo LIKE N'%' + @search + '%'
          OR f.Ad      LIKE N'%' + @search + '%'
          OR n.Numune_Adi LIKE N'%' + @search + '%'
        )`
      : "";

    const baseQuery = `
      FROM NKR n
      LEFT JOIN RootTedarikci f  ON f.ID  = n.Firma_ID
      LEFT JOIN NumuneDetay   d  ON n.ID  = d.RaporID
      LEFT JOIN RootTedarikci p  ON d.ProjeID = p.ID
      LEFT JOIN Odeme         o  ON o.Evrak_No = n.Evrak_No
      LEFT JOIN Numune_Grup   g  ON n.Grup = g.Grup
      WHERE n.Durum = 'Aktif'
      ${searchClause}
    `;

    const req = pool.request()
      .input("search", search)
      .input("offset", offset)
      .input("limit",  limit);

    const countResult = await req.query(
      `SELECT COUNT(DISTINCT n.ID) AS total ${baseQuery}`
    );
    const total = countResult.recordset[0].total;

    const dataResult = await req.query(`
      SELECT
        n.ID,
        CONVERT(varchar(10), n.Tarih, 120) AS Tarih,
        n.Evrak_No,
        n.RaporNo,
        f.Ad    AS FirmaAd,
        p.Ad    AS ProjeAd,
        n.Numune_Adi,
        n.Grup,
        g.Tur,
        o.Odeme_Durumu
      ${baseQuery}
      ORDER BY n.RaporNo DESC
      OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY
    `);

    return Response.json({
      data: dataResult.recordset,
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit),
    });
  } catch (e: any) {
    return Response.json({ error: e.message }, { status: 500 });
  }
}

// ----------------------------------------------------------------
// POST /api/numune-kabul  (yeni numune ekle)
// ----------------------------------------------------------------
export async function POST(request: Request) {
  const session = await getServerSession(authOptions);
  if (!session) return Response.json({ error: "Yetkisiz erişim" }, { status: 401 });

  try {
    const body = await request.json();
    const { Tarih, Evrak_No, RaporNo, Firma_ID, Numune_Adi, Grup } = body;

    if (!Evrak_No?.trim())  return Response.json({ error: "Evrak No zorunludur."  }, { status: 400 });
    if (!RaporNo?.trim())   return Response.json({ error: "Rapor No zorunludur."  }, { status: 400 });
    if (!Numune_Adi?.trim()) return Response.json({ error: "Numune Adı zorunludur." }, { status: 400 });

    const pool = await poolPromise;
    const result = await pool.request()
      .input("Tarih",     Tarih     || null)
      .input("Evrak_No",  Evrak_No.trim())
      .input("RaporNo",   RaporNo.trim())
      .input("Firma_ID",  Firma_ID  ? parseInt(Firma_ID) : null)
      .input("Numune_Adi", Numune_Adi.trim())
      .input("Grup",      Grup      || null)
      .input("Durum",     "Aktif")
      .query(`
        INSERT INTO NKR (Tarih, Evrak_No, RaporNo, Firma_ID, Numune_Adi, Grup, Durum)
        OUTPUT INSERTED.ID
        VALUES (@Tarih, @Evrak_No, @RaporNo, @Firma_ID, @Numune_Adi, @Grup, @Durum)
      `);

    return Response.json({ id: result.recordset[0].ID }, { status: 201 });
  } catch (e: any) {
    return Response.json({ error: e.message }, { status: 500 });
  }
}

import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import NumuneKabulTable from "./NumuneKabulTable";
import styles from "@/app/styles/table.module.css";

export const metadata = { title: "Numune Kabul" };

export default async function NumuneKabulPage() {
  await getServerSession(authOptions);

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div>
          <h1 className={styles.pageTitle}>Numune Kabul</h1>
          <p className={styles.pageSubtitle}>
            Laboratuvara kabul edilen numunelerin takibi ve yönetimi.
          </p>
        </div>
      </div>
      <NumuneKabulTable />
    </div>
  );
}

