import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import poolPromise from "@/lib/db";
import { type NextRequest } from "next/server";

// ----------------------------------------------------------------
// GET  /api/numune-kabul?search=&page=1&limit=20
//
// Duplicate önlemi: NumuneDetay ve Odeme JOIN'leri yerine correlated
// subquery kullanılır → her NKR satırı kesin olarak bir kez gelir.
// ----------------------------------------------------------------
export async function GET(request: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session) return Response.json({ error: "Yetkisiz erişim" }, { status: 401 });

  const sp     = request.nextUrl.searchParams;
  const search = sp.get("search")?.trim() || "";
  const page   = Math.max(1, parseInt(sp.get("page")  || "1",  10));
  const limit  = Math.min(100, Math.max(5, parseInt(sp.get("limit") || "20", 10)));
  const offset = (page - 1) * limit;

  try {
    const pool = await poolPromise;

    // Arama: yalnızca NKR ve Firma kolonları — JOIN duplicate'i yok
    const searchClause = search
      ? `AND (
          n.Evrak_No     LIKE N'%' + @search + '%'
          OR n.RaporNo   LIKE N'%' + @search + '%'
          OR f.Ad        LIKE N'%' + @search + '%'
          OR n.Numune_Adi LIKE N'%' + @search + '%'
        )`
      : "";

    const whereClause = `
      WHERE n.Durum = 'Aktif'
      ${searchClause}
    `;

    // Firma JOIN'i arama için gerekli, duplicate üretmez (1:1 ilişki)
    const fromClause = `
      FROM NKR n
      LEFT JOIN RootTedarikci f  ON f.ID = n.Firma_ID
      LEFT JOIN Numune_Grup   g  ON n.Grup = g.Grup
    `;

    const req = pool.request()
      .input("search", search)
      .input("offset", offset)
      .input("limit",  limit);

    const countResult = await req.query(
      `SELECT COUNT(*) AS total ${fromClause} ${whereClause}`
    );
    const total = countResult.recordset[0].total;

    // ProjeAd ve Odeme_Durumu: correlated subquery → kesinlikle 1 satır
    const dataResult = await req.query(`
      SELECT
        n.ID,
        CONVERT(varchar(10), n.Tarih, 120)                                AS Tarih,
        n.Evrak_No,
        n.RaporNo,
        f.Ad                                                               AS FirmaAd,
        (
          SELECT TOP 1 rt.Ad
          FROM   NumuneDetay nd
          LEFT JOIN RootTedarikci rt ON nd.ProjeID = rt.ID
          WHERE  nd.RaporID = n.ID
        )                                                                  AS ProjeAd,
        n.Numune_Adi,
        n.Grup,
        g.Tur,
        (
          SELECT TOP 1 Odeme_Durumu
          FROM   Odeme
          WHERE  Evrak_No = n.Evrak_No
          ORDER BY ID DESC
        )                                                                  AS Odeme_Durumu
      ${fromClause}
      ${whereClause}
      ORDER BY n.Evrak_No DESC, n.RaporNo DESC
      OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY
    `);

    return Response.json({
      data: dataResult.recordset,
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit),
    });
  } catch (e: any) {
    return Response.json({ error: e.message }, { status: 500 });
  }
}

