    const countResult = await req1.query(
      `SELECT COUNT(DISTINCT n.Evrak_No) AS total ${baseJoin}`
    );
    if (signal.aborted) return new Response(null, { status: 499 });
    const total = countResult.recordset[0].total;

    // ── Query 2: Sayfalanmış gruplar ──
    const req2 = pool.request()
      .input("search", search)
      .input("offset", offset)
      .input("limit",  limit);

    const groupResult = await req2.query(`
