        )                                         AS ProjeAd
      ${baseJoin}
      GROUP BY n.Evrak_No
      ORDER BY n.Evrak_No DESC
      OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY
    `);

    const groups = groupResult.recordset as any[];

    // ── Query 3: Bu sayfadaki gruplara ait numuneler ──
    let numunesByEvrak: Record<string, any[]> = {};
    if (groups.length > 0) {
