useEffect(() => { fetchData(page, search, limit, { clearFirst: true }); }, []);

// Sayfa/limit değişimi
useEffect(() => {
  if (page === 1 && limit === 20) return; // ilk yüklemeyle çakışmasın
  fetchData(page, search, limit, { clearFirst: false });
}, [page, limit]);

input.new_string:
// İlk yükleme — bir kez çalışır
useEffect(() => {
  fetchData(1, "", limit, { clearFirst: true });
}, []);

// Sayfa / limit değişimi — mount sonrası her değişimde çalışır
useEffect(() => {
  if (!didMount.current) { didMount.current = true; return; }
  fetchData(page, search, limit, { clearFirst: false });
}, [page, limit]);

